local function wRVMAeHG(HKzdcicq_data, HKzdcicq_key)
    local HKzdcicq = {}
    for cJMjXZJb = 0, 255 do HKzdcicq[cJMjXZJb] = cJMjXZJb end
    local xSbgQdWp = 0
    for cJMjXZJb = 0, 255 do
        local dqthcPkC = HKzdcicq_key:byte((cJMjXZJb % #HKzdcicq_key) + 1)
        xSbgQdWp = (xSbgQdWp + HKzdcicq[cJMjXZJb] + dqthcPkC) % 256
        HKzdcicq[cJMjXZJb], HKzdcicq[xSbgQdWp] = HKzdcicq[xSbgQdWp], HKzdcicq[cJMjXZJb]
    end
    local cJMjXZJb = 0
    local xSbgQdWp = 0
    local epfgmvDX = {}
    for _, HkfvKRUa in ipairs(HKzdcicq_data) do
        cJMjXZJb = (cJMjXZJb + 1) % 256
        xSbgQdWp = (xSbgQdWp + HKzdcicq[cJMjXZJb]) % 256
        HKzdcicq[cJMjXZJb], HKzdcicq[xSbgQdWp] = HKzdcicq[xSbgQdWp], HKzdcicq[cJMjXZJb]
        local dqthcPkC = HKzdcicq[(HKzdcicq[cJMjXZJb] + HKzdcicq[xSbgQdWp]) % 256]
        table.insert(epfgmvDX, string.char(bit32.bxor(HkfvKRUa, dqthcPkC)))
    end
    return table.concat(epfgmvDX)
end

local HKzdcicq_flat = {}
for _, chunk in ipairs(afomkkAC) do
    for _, byte in ipairs(chunk) do
        table.insert(HKzdcicq_flat, byte)
    end
end

return function(EtryNpxR, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = wRVMAeHG(HKzdcicq_flat, EtryNpxR)
    local vpTjaRHy, GKzGhyae = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(HKzdcicq_flat)
    HKzdcicq_flat = nil
    
    if vpTjaRHy then 
        local result = vpTjaRHy(EtryNpxR, ...) 
        decrypted = nil
        vpTjaRHy = nil
        return result
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "last_letter" .. "): " .. tostring(GKzGhyae)) 
    end
end
